  1→import { useCallback, useEffect, useRef, useState } from 'react';
  2→import type { ClipboardEntry } from '../data/clipboard_data';
  3→import { MOCK_CLIPBOARD_ENTRIES } from '../data/clipboard_data';
  4→import type { ClipboardChangeEvent } from '../platform';
  5→import { getPlatform, isTauri } from '../platform';
  6→import type { ClipboardEntryRow } from '../utils/database';
  7→import { clipboardDb } from '../utils/database';
  8→
  9→const MAX_ENTRIES = 1000;
 10→
 11→function rowToEntry(row: ClipboardEntryRow): ClipboardEntry {
 12→  const date = new Date(row.copied_at);
 13→  return {
 14→    id: row.id,
 15→    content: row.content,
 16→    contentType: row.content_type as ClipboardEntry['contentType'],
 17→    sourceApp: row.source_app,
 18→    sourceIcon: null,
 19→    copiedAt: isNaN(date.getTime()) ? new Date() : date,
 20→    pinned: row.pinned === 1,
 21→  };
 22→}
 23→
 24→function entryToRow(entry: ClipboardEntry): ClipboardEntryRow {
 25→  return {
 26→    id: entry.id,
 27→    content: entry.content,
 28→    content_type: entry.contentType,
 29→    source_app: entry.sourceApp,
 30→    copied_at: entry.copiedAt.toISOString(),
 31→    pinned: entry.pinned ? 1 : 0,
 32→  };
 33→}
 34→
 35→function createEntryFromEvent(event: ClipboardChangeEvent): ClipboardEntry {
 36→  return {
 37→    id: `clip-${event.timestamp}-${Math.random().toString(36).slice(2, 8)}`,
 38→    content: event.content,
 39→    contentType: event.contentType,
 40→    sourceApp: 'System',
 41→    sourceIcon: null,
 42→    copiedAt: new Date(event.timestamp),
 43→    pinned: false,
 44→  };
 45→}
 46→
 47→function trimToMaxEntries(entries: ClipboardEntry[]): ClipboardEntry[] {
 48→  if (entries.length <= MAX_ENTRIES) return entries;
 49→  const pinned = entries.filter(e => e.pinned);
 50→  const unpinned = entries.filter(e => !e.pinned);
 51→  const unpinnedLimit = Math.max(0, MAX_ENTRIES - pinned.length);
 52→  return [
 53→    ...pinned,
 54→    ...unpinned.slice(0, unpinnedLimit),
 55→  ];
 56→}
 57→
 58→export function useClipboardHistory() {
 59→  const [entries, setEntries] = useState<ClipboardEntry[]>([]);
 60→  const loadedRef = useRef(false);
 61→
 62→  useEffect(() => {
 63→    if (loadedRef.current) return;
 64→    loadedRef.current = true;
 65→
 66→    clipboardDb.getAll(MAX_ENTRIES).then(rows => {
 67→      if (rows.length > 0) {
 68→        setEntries(rows.map(rowToEntry));
 69→      } else if (!isTauri) {
 70→        const mock = MOCK_CLIPBOARD_ENTRIES.map(e => ({ ...e }));
 71→        setEntries(mock);
 72→        for (const entry of mock) {
 73→          clipboardDb.insert(entryToRow(entry));
 74→        }
 75→      }
 76→    });
 77→  }, []);
 78→
 79→  useEffect(() => {
 80→    if (!isTauri) return;
 81→
 82→    let unsubscribe: (() => void) | undefined;
 83→    let cancelled = false;
 84→
 85→    getPlatform()
 86→      .clipboard.onClipboardChange((event: ClipboardChangeEvent) => {
 87→        if (cancelled) return;
 88→
 89→        setEntries(prev => {
 90→          const existing = prev.find(
 91→            e => e.content === event.content && !e.pinned,
 92→          );
 93→
 94→          let next: ClipboardEntry[];
 95→          if (existing) {
 96→            const updated = {
 97→              ...existing,
 98→              copiedAt: new Date(event.timestamp),
 99→            };
100→            next = [
101→              updated,
102→              ...prev.filter(e => e.id !== existing.id),
103→            ];
104→            clipboardDb.update(existing.id, {
105→              copied_at: updated.copiedAt.toISOString(),
106→            });
107→          } else {
108→            const newEntry = createEntryFromEvent(event);
109→            next = [
110→              newEntry,
111→              ...prev,
112→            ];
113→            clipboardDb.insert(entryToRow(newEntry));
114→          }
115→
116→          next = trimToMaxEntries(next);
117→          return next;
118→        });
119→      })
120→      .then(unsub => {
121→        if (cancelled) {
122→          unsub();
123→        } else {
124→          unsubscribe = unsub;
125→        }
126→      });
127→
128→    return () => {
129→      cancelled = true;
130→      unsubscribe?.();
131→    };
132→  }, []);
133→
134→  const togglePin = useCallback((entryId: string) => {
135→    setEntries(prev => {
136→      const entry = prev.find(e => e.id === entryId);
137→      if (!entry) return prev;
138→      const newPinned = !entry.pinned;
139→      clipboardDb.update(entryId, { pinned: newPinned ? 1 : 0 });
140→      return prev.map(e =>
141→        e.id === entryId
142→          ? {
143→              ...e,
144→              pinned: newPinned,
145→            }
146→          : e);
147→    });
148→  }, []);
149→
150→  const deleteEntry = useCallback((entryId: string) => {
151→    setEntries(prev => {
152→      clipboardDb.delete(entryId);
153→      return prev.filter(e => e.id !== entryId);
154→    });
155→  }, []);
156→
157→  const clearAll = useCallback(() => {
158→    setEntries([]);
159→    clipboardDb.clear();
160→  }, []);
161→
162→  return {
163→    entries,
164→    togglePin,
165→    deleteEntry,
166→    clearAll,
167→  };
168→}
